function readEnv(name) {
  try {
    const fromN8n = typeof $env !== 'undefined' ? $env[name] : undefined;
    if (fromN8n !== undefined && fromN8n !== null && String(fromN8n).trim()) {
      return String(fromN8n).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}
function workflowName() {
  try {
    if (typeof $workflow !== 'undefined' && $workflow && $workflow.name) {
      return String($workflow.name).trim();
    }
  } catch (e) {}
  return '';
}
function isDevWorkflow() {
  return /^DEV\s*-/i.test(workflowName());
}
const wh = $input.first().json;
const got = String(
  wh.headers?.['x-webhook-secret'] || wh.headers?.['X-Webhook-Secret'] || ''
).trim();
const want = isDevWorkflow()
  ? readEnv('CDP_DEV_MUVSTOK_CALLBACK_WEBHOOK_SECRET') ||
    readEnv('CDP_MUVSTOK_CALLBACK_WEBHOOK_SECRET') ||
    readEnv('CALLBACK_WEBHOOK_SECRET') ||
    readEnv('CDP_CALLBACK_WEBHOOK_SECRET') ||
    readEnv('N8N_WEBHOOK_SECRET') ||
    ''
  : readEnv('CDP_MUVSTOK_CALLBACK_WEBHOOK_SECRET') ||
    readEnv('CALLBACK_WEBHOOK_SECRET') ||
    readEnv('CDP_CALLBACK_WEBHOOK_SECRET') ||
    readEnv('N8N_WEBHOOK_SECRET') ||
    '';
return [{ json: { ...wh, authorized: !!want && got === want, secret_configured: !!want, secret_received: !!got } }];

// --- muvstok_sheet_helpers (auto) ---
// Shared helpers for n8n API Diversos receiver Code nodes (Detalhado + Resumo).
// Injected by scripts/patch_muvstok_receiver_workflow.py — do not edit workflow JSON by hand.

/** User-facing labels written to Google Sheets (not internal webhook paths). */
const CDP_SITE_CODE = 'api-diversos';
const CDP_SITE_LABEL = 'API Diversos';
const CDP_ORIGEM_LABEL = 'API Diversos';

/**
 * tipoEstoque codes used in titulo_bruto suffix.
 * NEW=0, VIVO=1, DORMENTE=2, MORTO=3, ESCRAPE=4
 */
const STOCK_TYPE_CODE_BY_NAME = {
  new: 0,
  novo: 0,
  vivo: 1,
  dormente: 2,
  morto: 3,
  escrape: 4,
  scrape: 4,
};

function pickField(row, ...keys) {
  if (!row || typeof row !== 'object') return null;
  for (const k of keys) {
    const v = row[k];
    if (v !== null && v !== undefined && v !== '') return v;
  }
  return null;
}

function readEnv(name) {
  try {
    const fromN8n = typeof $env !== 'undefined' ? $env[name] : undefined;
    if (fromN8n !== undefined && fromN8n !== null && String(fromN8n).trim()) {
      return String(fromN8n).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}

function stockQty(row) {
  if (!row || typeof row !== 'object') return 0;
  const raw = pickField(
    row,
    'qtdeEstoque',
    'qtdEstoque',
    'quantidadeEstoque',
    'quantidade',
    'qtde',
    'qtd',
    'stock_quantity',
    'estoque'
  );
  const n = Number(raw);
  return Number.isFinite(n) ? n : 0;
}

function isEmEstoque(row) {
  return stockQty(row) >= 1;
}

function filterInStock(listings) {
  return (Array.isArray(listings) ? listings : []).filter((row) => isEmEstoque(row));
}

function parsePrice(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  if (Number.isFinite(n) && n > 0) return n;
  const s = String(v).trim().replace(/\s/g, '');
  const br = s.replace(/\./g, '').replace(',', '.');
  const n2 = Number(br);
  return Number.isFinite(n2) && n2 > 0 ? n2 : null;
}

function salePriceFromRow(row) {
  return parsePrice(
    pickField(row, 'valorPrecoVenda', 'valorprecovenda', 'valorprecavenda', 'price', 'preco')
  );
}

function costPriceFromRow(row) {
  return parsePrice(
    pickField(row, 'valorCustoMedio', 'valorcustomedio', 'average_cost', 'custo')
  );
}

function rowHasAnyPrice(row) {
  return salePriceFromRow(row) !== null || costPriceFromRow(row) !== null;
}

/** Rows used for best-price: in-stock first; else any row with sale or cost price. */
function rowsForPricing(listings) {
  const arr = Array.isArray(listings) ? listings : [];
  const inStock = filterInStock(arr);
  if (inStock.length) return inStock;
  return arr.filter((row) => row && typeof row === 'object' && rowHasAnyPrice(row));
}

function normalizeStockTypeKey(raw) {
  return String(raw)
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

/** Sheet value: 0–4 as string, or '' if unknown. */
function stockTypeCode(row) {
  const raw = pickField(row, 'tipoEstoque', 'tipoestoque', 'stock_type');
  if (raw === null || raw === undefined || raw === '') return '';
  const n = Number(raw);
  if (Number.isFinite(n) && n >= 0 && n <= 4) return String(Math.round(n));
  const key = normalizeStockTypeKey(raw);
  if (key in STOCK_TYPE_CODE_BY_NAME) return String(STOCK_TYPE_CODE_BY_NAME[key]);
  return '';
}

function formatPriceBr(n) {
  if (n === null || n === undefined || !Number.isFinite(n)) return '';
  return Number(n).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

/** Detalhado preco = valorPrecoVenda (always; no tipoEstoque rule). */
function naSalePriceFromRow(row) {
  const p = salePriceFromRow(row);
  if (p === null) return '';
  return formatPriceBr(p);
}

/** Detalhado preco-medio = valorCustoMedio. */
function naCostPriceFromRow(row) {
  const p = costPriceFromRow(row);
  if (p === null) return '';
  return formatPriceBr(p);
}

function formatResumoPreco(n) {
  if (n === null || n === undefined || !Number.isFinite(n)) return 'N/A';
  return 'R$ ' + formatPriceBr(n);
}

function branchLabel(row) {
  return String(
    pickField(row, 'nomeFilial', 'nomefilial', 'branch_name', 'apelidoFilial', 'apelidofilial') || ''
  ).trim();
}

function companyLabel(row) {
  return String(
    pickField(
      row,
      'razaoSocial',
      'razaosocial',
      'razao_social',
      'nomeEmpresa',
      'nomeempresa',
      'empresa',
      'company_name',
      'seller_company_name',
      'nomeFornecedor',
      'nomefornecedor',
      'fornecedor',
      'nomeLoja',
      'nomeloja',
      'loja',
      'nomeFilial',
      'nomefilial',
      'branch_name',
      'apelidoFilial',
      'apelidofilial'
    ) || ''
  ).trim();
}

const BRAZIL_STATE_UF = {
  acre: 'AC',
  alagoas: 'AL',
  amapa: 'AP',
  amazonas: 'AM',
  bahia: 'BA',
  ceara: 'CE',
  'distrito federal': 'DF',
  'espirito santo': 'ES',
  goias: 'GO',
  maranhao: 'MA',
  'mato grosso': 'MT',
  'mato grosso do sul': 'MS',
  'minas gerais': 'MG',
  para: 'PA',
  paraiba: 'PB',
  parana: 'PR',
  pernambuco: 'PE',
  piaui: 'PI',
  'rio de janeiro': 'RJ',
  'rio grande do norte': 'RN',
  'rio grande do sul': 'RS',
  rondonia: 'RO',
  roraima: 'RR',
  'santa catarina': 'SC',
  'sao paulo': 'SP',
  sergipe: 'SE',
  tocantins: 'TO',
};
const BRAZIL_UFS = new Set(Object.values(BRAZIL_STATE_UF));

function normalizeTextKey(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

function normalizeUf(value) {
  const text = String(value || '').trim().toUpperCase();
  if (BRAZIL_UFS.has(text)) return text;
  const normalized = normalizeTextKey(value);
  if (BRAZIL_STATE_UF[normalized]) return BRAZIL_STATE_UF[normalized];
  const match = normalized
    .toUpperCase()
    .match(/\b(AC|AL|AP|AM|BA|CE|DF|ES|GO|MA|MT|MS|MG|PA|PB|PR|PE|PI|RJ|RN|RS|RO|RR|SC|SP|SE|TO)\b/);
  if (match) return match[1];
  for (const [state, uf] of Object.entries(BRAZIL_STATE_UF)) {
    if (normalized.includes(state)) return uf;
  }
  return '';
}

function sellerUf(row) {
  return normalizeUf(
    pickField(
      row,
      'uf',
      'UF',
      'estado',
      'Estado',
      'seller_uf',
      'seller_state',
      'state',
      'ufFilial',
      'uffilial',
      'estadoFilial',
      'estadofilial',
      'localizacao',
      'localização',
      'location',
      'cidade',
      'municipio',
      'município',
      'endereco',
      'endereço'
    ) || ''
  );
}

function normalizeCnpj(value) {
  const text = String(value || '');
  const match = text.match(/\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}/);
  if (!match) return '';
  const digits = match[0].replace(/\D/g, '');
  return digits.length === 14 ? digits : '';
}

function cnpjFromRow(row) {
  return normalizeCnpj(
    pickField(
      row,
      'cnpj',
      'CNPJ',
      'seller_cnpj',
      'cnpjFilial',
      'cnpjfilial',
      'cnpjEmpresa',
      'cnpjempresa',
      'cnpjFornecedor',
      'cnpjfornecedor',
      'documento',
      'document',
      'tax_id'
    ) || ''
  );
}

function brandLabel(row) {
  return String(
    pickField(row, 'fabricante', 'montadora', 'automaker', 'marca', 'brand') || ''
  ).trim();
}

function productTitle(row) {
  const name = String(pickField(row, 'produto', 'product_name', 'descricao') || '').trim();
  const tipoCode = stockTypeCode(row);
  if (!tipoCode) return name;
  if (!name) return '[' + tipoCode + ']';
  return name + ' [' + tipoCode + ']';
}

/** API Diversos has no product URL — Detalhado url_produto and Resumo LINK stay empty. */
function productUrlForSheet(_sku, _row) {
  return '';
}

/** @deprecated — seller contact no longer written to sheets */
function buildContactInfo(_sku, _row) {
  return productUrlForSheet();
}

/** @deprecated */
function buildProductUrl(sku, row) {
  return productUrlForSheet(sku, row);
}

function buildDemandUrl(sku) {
  const base = (
    readEnv('MUVSTOK_BASE_URL') ||
    readEnv('CDP_MUVSTOK_DEMAND_BASE') ||
    'https://data-bi.muvstok.com.br/api/Demand'
  )
    .trim()
    .replace(/\/+$/, '');
  const code = String(sku || '').trim();
  return code ? base + '/?sku=' + encodeURIComponent(code) : base;
}

function parseIsoMs(value) {
  if (!value) return NaN;
  const s = String(value).trim();
  if (!s) return NaN;
  const normalized = s.includes('T') ? s.replace('Z', '+00:00') : s;
  const ms = Date.parse(normalized);
  return Number.isFinite(ms) ? ms : NaN;
}

function resolveJobDurationSeconds(payload, meta, completedAt, startedAt) {
  const fromApi = Number(payload?.duration_seconds);
  if (Number.isFinite(fromApi) && fromApi > 0) {
    return Math.round(fromApi * 100) / 100;
  }
  const endMs = parseIsoMs(completedAt || payload?.completed_at);
  const startMs = parseIsoMs(
    startedAt || payload?.started_at || meta?.dispatched_at || meta?.processing_started_at
  );
  if (Number.isFinite(endMs) && Number.isFinite(startMs) && endMs >= startMs) {
    return Math.round(((endMs - startMs) / 1000) * 100) / 100;
  }
  return 0;
}

function skuSearchTimeMs(skuResult) {
  const ms = Number(skuResult?.duration_ms);
  return Number.isFinite(ms) && ms >= 0 ? Math.round(ms) : 0;
}

/** Resumo MELHOR PREÇO = lowest valorPrecoVenda across priced in-stock rows. */
function bestOfferFromListings(listings) {
  const priced = rowsForPricing(listings);
  let bestPrice = null;
  let bestSite = '';
  for (const row of priced) {
    if (!row || typeof row !== 'object') continue;
    const p = salePriceFromRow(row);
    if (p === null) continue;
    if (bestPrice === null || p < bestPrice) {
      bestPrice = p;
      bestSite = branchLabel(row) || CDP_SITE_LABEL;
    }
  }
  return { bestPrice, bestSite };
}

function normalizeResultStatus(value, rows) {
  const raw = String(value || '').trim().toUpperCase();
  if (
    raw === 'FOUND_PRICE' ||
    raw === 'NO_PRICE' ||
    raw === 'NOT_FOUND' ||
    raw === 'BLOCKED' ||
    raw === 'TIMEOUT' ||
    raw === 'ERROR' ||
    raw === 'NOT_QUERIED'
  ) {
    return raw;
  }
  const lower = String(value || '').trim().toLowerCase();
  if (lower.includes('blocked') || lower.includes('captcha') || lower.includes('403')) return 'BLOCKED';
  if (lower.includes('timeout')) return 'TIMEOUT';
  if (lower.includes('error') || lower.includes('failed') || lower.includes('http_')) return 'ERROR';
  if (lower.includes('not_found') || lower.includes('not found') || lower.includes('no_results')) return 'NOT_FOUND';
  if (lower.includes('no_price') || lower.includes('sem_preco')) return 'NO_PRICE';
  const arr = Array.isArray(rows) ? rows : [];
  if (!arr.length) return 'NOT_FOUND';
  return hasValidPrice(rows) ? 'FOUND_PRICE' : 'NO_PRICE';
}

function normalizeSourceHealth(value, skuResult) {
  const raw = String(value || skuResult?.source_health || '').trim().toUpperCase();
  if (raw === 'OK' || raw === 'WORKING') return 'WORKING';
  if (raw === 'BLOCKED' || raw === 'TIMEOUT' || raw === 'ERROR' || raw === 'NOT_QUERIED') return raw;
  const result = normalizeResultStatus(skuResult?.sku_result || skuResult?.status || '', skuResult?.rows);
  if (result === 'BLOCKED' || result === 'TIMEOUT' || result === 'ERROR' || result === 'NOT_QUERIED') {
    return result;
  }
  return 'WORKING';
}

function hasValidPrice(rows) {
  return rowsForPricing(rows).some((row) => salePriceFromRow(row) !== null);
}

function sheetStatusForResult(resultStatus, hasPrice) {
  const raw = String(resultStatus || '').trim().toUpperCase();
  const lower = String(resultStatus || '').trim().toLowerCase();
  const status = normalizeResultStatus(resultStatus, []);
  const explicitNegative =
    raw === 'NO_PRICE' ||
    raw === 'NOT_FOUND' ||
    raw === 'BLOCKED' ||
    raw === 'TIMEOUT' ||
    raw === 'ERROR' ||
    raw === 'NOT_QUERIED' ||
    lower.includes('no_price') ||
    lower.includes('sem_preco') ||
    lower.includes('not_found') ||
    lower.includes('not found') ||
    lower.includes('blocked') ||
    lower.includes('captcha') ||
    lower.includes('timeout') ||
    lower.includes('error') ||
    lower.includes('failed') ||
    lower.includes('http_');
  if (status === 'FOUND_PRICE' || (hasPrice && !explicitNegative)) return '✅ Encontrado';
  if (status === 'NO_PRICE') return '⚠️ Sem preço';
  if (status === 'BLOCKED') return '🚫 Bloqueado';
  if (status === 'TIMEOUT' || status === 'ERROR') return '⚠️ Erro';
  return '❌ Não encontrado';
}

function availabilityForResult(resultStatus, stock) {
  const status = normalizeResultStatus(resultStatus, []);
  if (status === 'FOUND_PRICE') return toAvailabilityPt(stock);
  if (status === 'NO_PRICE') return 'sem_preco';
  if (status === 'BLOCKED') return 'bloqueado';
  if (status === 'TIMEOUT') return 'timeout';
  if (status === 'ERROR') return 'erro';
  if (status === 'NOT_QUERIED') return 'sem_resultados';
  return 'nao_encontrado';
}

function rawTitleForResult(resultStatus, fallback) {
  const status = normalizeResultStatus(resultStatus, []);
  const message = String(fallback || status || '').trim();
  if (status === 'BLOCKED') return 'BLOQUEADO: ' + (message || 'API Diversos bloqueado');
  if (status === 'TIMEOUT') return 'TIMEOUT: ' + (message || 'API Diversos timeout');
  if (status === 'ERROR') return 'ERRO: ' + (message || 'API Diversos erro');
  if (status === 'NO_PRICE') return 'SEM_PRECO: ' + (message || 'API Diversos sem preço');
  if (status === 'NOT_FOUND') return 'NOT_FOUND';
  return message || status;
}
// --- end muvstok_sheet_helpers ---

function parseBody(raw) {
  let p = raw;
  if (typeof p === 'string') {
    try { p = JSON.parse(p); } catch (e) { p = {}; }
  }
  return p && typeof p === 'object' ? p : {};
}
function na(v) {
  if (v === null || v === undefined || v === '') return '';
  return String(v);
}
function toBoolPt(v) { return v ? 'SIM' : 'NAO'; }
function toAvailabilityPt(stock) {
  const n = Number(stock);
  if (!Number.isFinite(n) || n < 1) return 'fora_de_estoque';
  return 'em_estoque';
}

const wh = $input.first().json;
const payload = parseBody(wh.body);
const q = wh.query || {};
const meta = typeof payload.metadata === 'object' && payload.metadata !== null ? payload.metadata : {};

const jobId = na(payload.job_id);
const correlationId = na(payload.correlation_id);
const jobStatus = na(payload.status || 'unknown');
const completedAt = na(payload.completed_at || new Date().toISOString());
const startedAt = na(payload.started_at || meta.dispatched_at || '');
const submitted = Number(payload.submitted_sku_count || payload.requested_skus || 0);
const succeeded = Number(payload.succeeded_sku_count || 0);
const failed = Number(payload.failed_sku_count || 0);
const errors = Array.isArray(payload.errors) ? payload.errors : [];
const jobDuration = resolveJobDurationSeconds(payload, meta, completedAt, startedAt);

let chatId = String(meta.chat_id || q.chat_id || '').trim();
let replyEmail = String(meta.reply_email || q.reply_email || '').trim();
let replyChannel = String(meta.reply_channel || q.reply_channel || meta.command_origin || q.command_origin || '').trim().toLowerCase();
let commandOrigin = String(meta.command_origin || q.command_origin || '').trim().toLowerCase();
let notify = String(meta.notify || q.notify || '').trim().toLowerCase();
if (!replyChannel) {
  if (notify === 'email' || replyEmail) replyChannel = 'email';
  else if (notify === 'telegram' || chatId) replyChannel = 'telegram';
}
if (!commandOrigin && replyChannel) commandOrigin = replyChannel;
if (replyChannel === 'email') {
  notify = 'email';
  commandOrigin = 'email';
  chatId = '';
} else if (replyChannel === 'telegram') {
  notify = 'telegram';
  commandOrigin = 'telegram';
  replyEmail = '';
} else if (!chatId && !replyEmail) {
  chatId = readEnv('TELEGRAM_DEFAULT_CHAT_ID');
  if (chatId) {
    notify = 'telegram';
    replyChannel = 'telegram';
    commandOrigin = commandOrigin || 'telegram';
  }
}
if (!notify) notify = chatId ? 'telegram' : replyEmail ? 'email' : 'none';

const rows = [];
const skuSummaries = {};
const skuList = [];

function pushDetalhado(base) {
  rows.push({ json: base });
}

function markSku(sku, status) {
  function normalizeSheetStatus(value) {
    let s = String(value || '').trim().toLowerCase();
    try { s = s.normalize('NFD').replace(/[\u0300-\u036f]/g, ''); } catch (e) {}
    s = s.replace(/[^a-z0-9]+/g, ' ').trim();
    if (!s) return '';
    if (s.includes('sem preco') || s.includes('sem melhor preco') || s.includes('s preco') || s.includes('no price')) return 'sem_preco';
    if (s.includes('nao encontrado') || s.includes('not found')) return 'nao_encontrado';
    if (s.includes('bloqueado') || s.includes('blocked')) return 'bloqueado';
    if (s.includes('encontrado') || s === 'found') return 'encontrado';
    if (s.includes('processando') || s.includes('processing')) return 'processando';
    return s;
  }
  function sheetStatusRank(value) {
    const ranks = { processando: 0, nao_encontrado: 1, bloqueado: 2, sem_preco: 3, encontrado: 4 };
    const key = normalizeSheetStatus(value);
    return Object.prototype.hasOwnProperty.call(ranks, key) ? ranks[key] : -1;
  }
  function chooseSheetStatus(current, candidate) {
    return sheetStatusRank(current) > sheetStatusRank(candidate) ? current : candidate;
  }

  const key = String(sku || '').trim().toUpperCase();
  if (!key) return;
  const next = String(status || '').trim() || '❌ Não encontrado';
  if (!skuSummaries[key]) {
    skuSummaries[key] = { sku: key, listing_count: 0, found: false, encontrado: '❌ Não encontrado' };
  }
  const chosen = chooseSheetStatus(skuSummaries[key].encontrado, next);
  skuSummaries[key].encontrado = chosen;
  const normalized = normalizeSheetStatus(chosen);
  skuSummaries[key].found = normalized === 'encontrado' || normalized === 'sem_preco';
  skuSummaries[key].listing_count += 1;
  if (!skuList.includes(key)) skuList.push(key);
}

function listingRow(sku, row, statusItem, searchTimeMs) {
  const skuSearched = na(sku).toUpperCase();
  const skuFound = na(pickField(row, 'sku', 'SKU', 'skuSemCaractereEspecial') || sku);
  const stock = pickField(row, 'qtdeEstoque', 'qtdEstoque', 'stock_quantity');
  const filial = branchLabel(row);
  const company = companyLabel(row);
  const empresa = (company && company !== filial) ? company : '';
  const saleStr = naSalePriceFromRow(row);
  const costStr = naCostPriceFromRow(row);
  const ms = Number(searchTimeMs);
  const resultStatus = saleStr ? 'FOUND_PRICE' : normalizeResultStatus(statusItem || 'NO_PRICE', [row]);
  const health = normalizeSourceHealth('', { sku_result: resultStatus });
  const hasPrice = saleStr !== '';
  const encontrado = sheetStatusForResult(resultStatus, hasPrice);
  const title = productTitle(row);
  return {
    job_id: jobId,
    sku_searched: skuSearched,
    sku_found: skuFound || 'N/A',
    exact_match: toBoolPt(skuFound && skuSearched === String(skuFound).trim().toUpperCase()),
    site: CDP_SITE_LABEL,
    price: saleStr,
    preco_medio: costStr,
    currency: 'BRL',
    seller: filial || 'N/A',
    uf: sellerUf(row),
    empresa: empresa,
    cnpj: cnpjFromRow(row),
    product_url: productUrlForSheet(skuSearched, row),
    regiao: 'Brasil',
    raw_title: title || (hasPrice ? '' : ''),
    scraped_at: completedAt,
    search_time_ms: String(Number.isFinite(ms) && ms >= 0 ? Math.round(ms) : 0),
    condition: 'novo',
    brand: brandLabel(row) || 'N/A',
    site_code: CDP_SITE_CODE,
    status_resultado: resultStatus,
    source_health: health,
    has_valid_price: hasPrice,
    fonte_pipeline: CDP_ORIGEM_LABEL,
    _encontrado: encontrado,
  };
}

const warehouseResults = Array.isArray(payload.results) ? payload.results : [];
if (warehouseResults.length) {
  for (const skuResult of warehouseResults) {
    const sku = na(skuResult.sku);
    const rawListings = Array.isArray(skuResult.rows)
      ? skuResult.rows
      : Array.isArray(skuResult.listings)
        ? skuResult.listings
        : [];
    const resultStatus = normalizeResultStatus(skuResult.sku_result || skuResult.status, rawListings);
    const sourceHealth = normalizeSourceHealth(skuResult.source_health, skuResult);
    const listings = rowsForPricing(rawListings);
    if (!listings.length) {
      const sheetStatus = sheetStatusForResult(resultStatus, false);
      markSku(sku, sheetStatus);
      pushDetalhado({
        job_id: jobId,
        sku_searched: sku,
        sku_found: 'N/A',
        exact_match: toBoolPt(false),
        site: 'API Diversos',
        price: 'N/A',
        preco_medio: 'N/A',
        currency: 'BRL',
        availability: availabilityForResult(resultStatus, 0),
        seller: 'N/A',
        uf: '',
        empresa: 'N/A',
        cnpj: '',
        product_url: productUrlForSheet(sku, null),
        origin: 'N/A',
        raw_title: rawTitleForResult(resultStatus, na(skuResult.error_code || skuResult.status || 'not_found')),
        scraped_at: completedAt,
        search_time_ms: String(skuSearchTimeMs(skuResult)),
