  const codigo = String(row.CODIGO == null ? '' : row.CODIGO).trim().toUpperCase();
  const u = byCodigo[codigo];
  if (!u) continue;
  const encontrado = chooseSheetStatus(pickSheetField(row, 'ENCONTRADO'), u.ENCONTRADO);
  out.push({
    json: { ...row, PROCESSADO: u.PROCESSADO, ENCONTRADO: encontrado },
    pairedItem: item.pairedItem ?? { item: i },
